<script>
/*Bloqueio de botão enviar sem checkbox "Acieto"*/
jQuery(document).ready(function(){

    var btn = 'form[name=Contact] button';      /*INFORME O SELETOR DO BOTÃO*/
    var checkbox = '#form-field-aceite';  /*INFORME O NOME DO ID DO CHECKBOX*/
    
    jQuery(btn).attr('disabled', 'disabled').css("opacity", "0.6");
   
    jQuery(checkbox).click(function(){
      
        if(jQuery(this).is(':checked')){
            
            jQuery(btn).removeAttr('disabled').css("opacity", "1");
        
        }else{
            
            jQuery(btn).attr('disabled', 'disabled').css("opacity", "0.6");
            
        }
        
    });
});
</script>

<!--Endereço por CEP-->

<script src="https://code.jquery.com/jquery-3.4.1.min.js"
            integrity="sha256-CSXorXvZcTkaix6Yvo6HppcZGetbYMGWSFlBw8HfCJo="
            crossorigin="anonymous"></script>

    <!-- Adicionando Javascript -->
    <script type="text/javascript" >

    	var $jq = jQuery.noConflict()

        $jq(document).ready(function() {

            function limpa_formulário_cep() {
                // Limpa valores do formulário de cep.
                $jq("#form-field-rua").val("");
                $jq("#form-field-bairro").val("");
                $jq("#form-field-cidade").val("");
                $jq("#form-field-uf").val("");
            }
            
            //Quando o campo cep perde o foco.
            $jq("#form-field-cep").blur(function() {

                //Nova variável "cep" somente com dígitos.
                var cep = $jq(this).val().replace(/\D/g, '');

                //Verifica se campo cep possui valor informado.
                if (cep != "") {

                    //Expressão regular para validar o CEP.
                    var validacep = /^[0-9]{8}$/;

                    //Valida o formato do CEP.
                    if(validacep.test(cep)) {

                        //Preenche os campos com "..." enquanto consulta webservice.
                        $jq("#form-field-rua").val("...");
                        $jq("#form-field-bairro").val("...");
                        $jq("#form-field-cidade").val("...");
                        $jq("#form-field-uf").val("...");

                        //Consulta o webservice viacep.com.br/
                        $jq.getJSON("https://viacep.com.br/ws/"+ cep +"/json/?callback=?", function(dados) {

                            if (!("erro" in dados)) {
                                //Atualiza os campos com os valores da consulta.
                                $jq("#form-field-rua").val(dados.logradouro);
                                $jq("#form-field-bairro").val(dados.bairro);
                                $jq("#form-field-cidade").val(dados.localidade);
                                $jq("#form-field-uf").val(dados.uf);
                            } //end if.
                            else {
                                //CEP pesquisado não foi encontrado.
                                limpa_formulário_cep();
                                alert("CEP não encontrado.");
                            }
                        });
                    } //end if.
                    else {
                        //cep é inválido.
                        limpa_formulário_cep();
                        alert("Formato de CEP inválido.");
                    }
                } //end if.
                else {
                    //cep sem valor, limpa formulário.
                    limpa_formulário_cep();
                }
            });
        });

    </script>"},"elements":[],"widgetType":"html"}],"isInner":true},{"id":"ac1f7a2","elType":"container","settings":[],"elements":[{"id":"7b9bc91d","elType":"widget","settings":{"editor":"Estamos entusiasmados com seu interesse em fazer parte da nossa equipe dedicada de segurança e limpeza. Aqui, valorizamos a integridade, a responsabilidade e a excelência no atendimento. Nosso compromisso é oferecer um ambiente de trabalho colaborativo, seguro e com oportunidades de crescimento.
